Exemplo de implementação (adaptar ao stack real):

```typescript
// routes/export.ts  (ou equivalente no projeto)
import { Router, Request, Response } from 'express';
import { db } from '../db';

const router = Router();

router.get('/export/user-activity', async (req: Request, res: Response) => {
  const rows = await db('user_activity').select('*');

  res.setHeader('Content-Disposition', 'attachment; filename="user-activity.csv"');
  res.setHeader('Content-Type', 'text/csv');

  if (rows.length === 0) {
    res.send('');
    return;
  }

  const headers = Object.keys(rows[0]);
  const csv = [
    headers.join(','),
    ...rows.map(row =>
      headers.map(h => JSON.stringify(row[h] ?? '')).join(',')
    ),
  ].join('\n');

  res.send(csv);
});

export default router;
```

